assertions.query:
SELECT id, code
						FROM unbounded_varchar_pk_items
						ORDER BY id;

SELECT id, payload
						FROM bytea_pk_items
						WHERE id = E'\\xCAFEBABE';

SELECT value::int
						FROM internal_char_cast_items
						WHERE id = 1;

SELECT id, amount::text
						FROM numeric_typmod_default_items
						ORDER BY id;

UPDATE varchar_array_append_typmod_items
						SET labels = array_append(labels, 'abcd')
						WHERE id = 1;

UPDATE varchar_array_prepend_typmod_items
						SET labels = array_prepend('abcd', labels)
						WHERE id = 1;

UPDATE varchar_array_cat_typmod_items
						SET labels = array_cat(labels, ARRAY['abcd'])
						WHERE id = 1;

UPDATE character_array_append_typmod_items
						SET labels = array_append(labels, 'abcd')
						WHERE id = 1;

UPDATE character_array_prepend_typmod_items
						SET labels = array_prepend('abcd', labels)
						WHERE id = 1;

SELECT ARRAY['abc']::varchar(3)[] @> ARRAY['abc']::varchar(3)[],
							ARRAY['a']::character(3)[] @> ARRAY['a  ']::character(3)[],
							ARRAY[1.23]::numeric(5,2)[] && ARRAY[1.23]::numeric(5,2)[];

SELECT count(DISTINCT labels)
						FROM (VALUES
							(ARRAY['a']::character(3)[]),
							(ARRAY['a  ']::character(3)[])
						) AS v(labels);

SELECT count(DISTINCT labels)
						FROM (VALUES
							(ARRAY['abc']::varchar(3)[]),
							(ARRAY['abc']::varchar(3)[])
						) AS v(labels);

SELECT count(DISTINCT labels)
						FROM (VALUES
							(ARRAY[1.23]::numeric(5,2)[]),
							(ARRAY[1.23]::numeric(5,2)[])
						) AS v(labels);

SELECT count(*)
						FROM (VALUES
							(ARRAY['abc']::varchar(3)[]),
							(ARRAY['abc']::varchar(3)[])
						) AS v(labels)
						GROUP BY labels;

SELECT id
						FROM varchar_array_where_items
						WHERE labels = ARRAY['abc']::varchar(3)[];

SELECT id, labels
						FROM varchar_array_order_items
						ORDER BY labels;

SELECT amounts::text
						FROM numeric_array_typmod_items
						ORDER BY id;

UPDATE numeric_array_append_typmod_items
						SET amounts = array_append(amounts, 999.995)
						WHERE id = 1;

UPDATE numeric_array_prepend_typmod_items
						SET amounts = array_prepend(999.995, amounts)
						WHERE id = 1;

UPDATE numeric_array_cat_typmod_items
						SET amounts = array_cat(amounts, ARRAY[999.995])
						WHERE id = 1;

SELECT id, amount::text
						FROM numeric_negative_scale_items
						ORDER BY id;

SELECT id, amount::text
						FROM numeric_large_scale_items
						ORDER BY id;

SELECT id, amount::text
						FROM numeric_special_value_items
						ORDER BY amount;

SELECT labels
						FROM multidimensional_array_items
						WHERE id = 1;

SELECT values_int[0], values_int[1], values_int[2],
							array_upper(values_int, 1)
						FROM array_lower_bound_items;
